var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......설명은 잘 들었습니다.","JPN":"……説明は聞きました。","ENG":"Thank you for your explanation.","TWN":"……我明白了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다른 세계에서 온 방문자라니...... 정말 믿기 힘든 이야기로군요.","JPN":"別の世界からの訪問者だなんて……実に信じがたい話ですね。","ENG":"Visitors from another world. This is hard to believe.","TWN":"來自另一個世界的訪客……真是個難以相信的說法呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래서 제게 제 4종 침식체 요격을 협조해 달라는 겁니까?","JPN":"それで、僕に第4種侵食体の迎撃を頼みたいと？","ENG":"Are you asking me to help you fight a Category 4 C.O.?","TWN":"所以妳想要我協助你們消滅4級侵蝕體？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 역시 카린 양처럼 요점 정리가 정확하시네요.","JPN":"ハハ、さすが呑み込みが早いのも、カリンさんにそっくりですね。","ENG":"Hah hah. You're as straightforward as Karin.","TWN":"哈哈，果然和卡琳小姐一樣會把握重點啊。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"말씀대로 지금은 한 손이라도 더 필요하니까요.","JPN":"今は猫の手も借りたいところですからね。","ENG":"Yes. We need all the help we can get.","TWN":"就像我剛才說的，我們現在急需人手。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 가벼운 태도는 뭡니까?!","JPN":"その軽々しい態度は何ですか！？","ENG":"What's up with your flippant attitude?","TWN":"這是什麼輕浮的態度？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신들이야말로 이 세계에 불필요한 재난을 가지고 온 당사자들입니다.","JPN":"あなた方こそ、この世界に災害をもたらした張本人じゃないですか。","ENG":"You've invited an unnecessary disaster into our world.","TWN":"你們是給這個世界帶來不必要災難的罪魁禍首。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그에 대한 자각이 있기는 한 겁니까!","JPN":"その自覚はあるんですか！","ENG":"Do you even feel sorry for that?","TWN":"難道對這點毫無自覺嗎！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그, 그야...... 그렇죠......","JPN":"そ、それは……そうでしたね……","ENG":"W-well... Yes...","TWN":"那，那是……確實……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"역시 그냥 없었던 일로! ......라는 건 어려울까요?","JPN":"やっぱり、なかったことに！　って難しいですかね？","ENG":"Can't we just forget it ever happened? ... We can't, can we?","TWN":"就當作沒發生這種事！……是不可能的吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당연하지 않습니까!","JPN":"当たり前じゃないですか！","ENG":"Of course not!","TWN":"這不是廢話嗎！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금도 믿기는 힘들지만 아마 당신이...... 이 세계의 저라고 생각되네요.","JPN":"今も信じられないですが、あなたは多分……この世界の私なんでしょうね。","ENG":"I still can't believe this, but it seems you're another me in this world.","TWN":"雖然現在還是很難相信，不過你似乎……就是另一個世界的我呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 말에 따르면 당신도 델타 세븐의 일원이라고 하더군요.","JPN":"シノンさんから聞いたのですが、あなたもデルタセブンの一員だとか。","ENG":"Shiyoung said you're in Delta Seven.","TWN":"聽時雨小姐說，你也是第七三角洲部隊的成員。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저 역시 저희 세계의 델타 세븐 부대의 일원이었습니다.","JPN":"私も、私たちの世界のデルタセブン所属でした。","ENG":"So am I, of my own world.","TWN":"我也是我們世界裡第七三角洲部隊的成員。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 무슨 상관입니까? 그런 건 우연에 불과합니다.","JPN":"何の関係があると？　そんなの、ただの偶然に過ぎません。","ENG":"What's that got to do with this? It's just a coincidence.","TWN":"那又怎樣？那不過是個巧合而已。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"흥미로운 이야기라는 건 인정하지만...... 지금 논의의 주제와는 상관 없는 일입니다.","JPN":"興味深い話なのは認めますが……今の論点とは何ら関係のないことです。","ENG":"I admit that it's intriguing just the same, but it has nothing to do with what we're discussing at the moment.","TWN":"我承認這是一個有趣的故事，但是……這與現在討論的主題無關。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저희 세계의 델타 세븐 대원들은...... 저 하나밖에 남지 않았습니다.","JPN":"私たちの世界のデルタセブンで生き残ったのは……私ひとりだけなんです。","ENG":"In our world... I'm the only one left of Delta Seven.","TWN":"我們世界的第七三角洲部隊成員……只剩下我一個人了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......네?","JPN":"……え？","ENG":"Pardon?","TWN":"……欸？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다른 대원들은 모두 저 <color=#ffd34c>네피림</color>과의 전투에서 전사했습니다.","JPN":"他の隊員は全員、あの<color=#ffd34c>ネフィリム</color>との戦闘で戦死しました。","ENG":"Everyone else died fighting that <color=#ffd34c>Nephil</color>.","TWN":"其他成員全部都在和 <color=#ffd34c>諾菲力</color>的戰鬥中陣亡了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇지 않았다면 이런 중요한 작전을 경박한 프리랜서 용병과 진행했을 리는 없겠죠.","JPN":"それがなければ、こんなに重要な作戦をあの軽薄なフリーランスの傭兵と行うわけがありません。","ENG":"If they hadn't, I would have been here with them instead of this brash mercenary for such an important operation.","TWN":"不然我怎麼可能會和那種輕浮的自由傭兵一起執行這麼重要的任務呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"경박하다니...... 사실이긴 하지만 좀 너무하네요.","JPN":"軽薄だなんて……事実ではありますが、あんまりです。","ENG":"Did you just call me brash? Even if that's true, it still hurts.","TWN":"竟然說我輕浮……雖然是事實，但還是有點過分呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래도 이런 생환율 0%의 작전까지 따라와 줬는데 말이죠.","JPN":"こんな生還率0％の作戦についてきてあげたというのに。","ENG":"I've followed you on this mission that has zero chance of survival.","TWN":"好歹我也參加了這個生還率近乎0%的作戰，跟到這個世界來了耶。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......말씀하신 대로 저흰 이 세계에서 용서받지 못할 범죄자들입니다.","JPN":"……おっしゃるとおり、私たちはこの世界では許されざる犯罪者です。","ENG":"As you said, we've committed an unforgivable crime against your world.","TWN":"……如你所說，我們在這個世界是無法被饒恕的罪人。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"거기에 대해서 변명할 생각은 없어요. 원한다면 어떤 책임이든 지도록 하겠습니다.","JPN":"それについて弁明するつもりはありません。お望みなら、どんな責任でもとりましょう。","ENG":"I'm not going to make excuses about that. I'll take responsibility however I can.","TWN":"我不會對此進行任何辯解。如果你希望的話，我願意承擔任何責任。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 만약 당신이 저와 닮은 존재라면......","JPN":"ですが、もしあなたが私と似た存在ならば……","ENG":"But... if you're really like me...","TWN":"但是如果你是與我相似的存在……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전우들의 희생으로 마련된 이번 작전이 어떤 의미인지도...... 조금은 이해해 주실 수 있지 않나요?","JPN":"戦友たちの犠牲によって立てられた今回の作戦が、どんな意味を持つか……少しはご理解いただけるのでは？","ENG":"I think you could understand how desperate I am not to fail this operation or let the deaths of my comrades go to waste, couldn't you?","TWN":"這場用戰友的犧牲換來的作戰到底有什麼樣的意義……你應該也能稍微理解一些吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"부탁드립니다! 저희에게 협력해 주세요!","JPN":"お願いします！　私たちに協力してください！","ENG":"Please! Help us!","TWN":"拜託了！請幫幫我們！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신과 제가 명백하게 다른 부분이 하나 있군요.","JPN":"あなたと僕で明らかに異なる点が一つありますね。","ENG":"You and I are different for one thing.","TWN":"我和妳有一點非常明顯的不同啊。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전 그런 감상적인 이유로 움직이지 않습니다.","JPN":"僕はそんな感傷的な理由では動きません。","ENG":"I don't let myself be moved by emotions.","TWN":"那就是我從來不會感情用事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 중장님께 배운 건, 규율이야말로 군인의 사명이라는 것입니다.","JPN":"僕が中将から学んだのは、規律こそが軍人の使命だということです。","ENG":"The Lieutenant General taught me that we soldiers must follow the rules, no matter what.","TWN":"紀律是士兵的使命，這是我從中將大人那裡學到的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하, 하지만......","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 중장님께선 이렇게도 말씀하셨습니다.","JPN":"あと、中将はこうもおっしゃいました。","ENG":"The Lieutenant General also said,","TWN":"並且，中將大人也這麼說過。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"외부의 위협으로부터 사람들을 지키는 것이야말로 군인이 짊어져야 할 가장 큰 의무라고.","JPN":"外部の脅威から人々を守ることこそが、軍人として果たすべき最も大きな義務だと。","ENG":"protecting people from external threats is the biggest duty of all soldiers.","TWN":"“保護人民避免受到外部威脅，才是軍人所背負的最大職責。”"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체가 날뛰게 내버려 두면 그 피해는 모두 민간인들이 받게 되겠죠.","JPN":"第4種侵食体が暴れるのを放置すれば、その被害はすべて民間人が被ることになるでしょう。","ENG":"If I let this Category 4 C.O. run amok, our civilians will take the brunt of damage.","TWN":"如果放任4級侵蝕體在這裡作亂，受到傷害的肯定都是平民百姓。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"델타 세븐의 대원으로서 그런 꼴을 두고 볼 수는 없습니다.","JPN":"デルタセブンの隊員として、そんな暴挙を見過ごすわけにはいきません。","ENG":"As a member of Delta Seven, I can't let that happen.","TWN":"作為第七三角洲部隊一員，對此我無法坐視不管。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니 지금은 사소한 문제들을 미뤄 두고 당신들에게 협력하겠습니다.","JPN":"ですから、今は些細なことは後回しにして、あなた方に協力します。","ENG":"So, for now, I'll put all the other issues aside and cooperate with you.","TWN":"所以現在先把這些小事情放一邊，我就和妳合作吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"역시! 가끔 대범해지는 것도 카린 양과 꼭 닮았다니까요?","JPN":"さすが！　決める時は決めるところも、カリンさんにそっくりですよ？","ENG":"I knew it! You're just like Karin, making bold decisions like that sometimes!","TWN":"果然！偶爾寬大的性格也和卡琳小姐一模一樣哦？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"너무 좋아하지 마시죠. 말 그대로 미뤄 두는 것뿐입니다.","JPN":"喜ぶのはまだ早いです。文字通り、後回しにするだけですからね。","ENG":"Don't be so excited. Like I said, I'm only putting other issues aside for now.","TWN":"別高興得太早。如我所說，你們遲早要付出代價，只不過是延後了而已。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일이 끝나고 나면 제 명예를 걸고 반드시 당신들을 법정에 세우도록 하겠습니다.","JPN":"この件が終われば、僕の名誉にかけてあなた方を必ず法廷に立たせますから。","ENG":"I swear on my honor that once this is done, I'm bringing you to justice.","TWN":"一切結束後，我一定會以我的名義把你們告上法庭。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"변명거리를 잘 생각해 두시는 게 좋을 겁니다.","JPN":"何て言い訳するか、今からよく考えておいたほうが良いでしょうね。","ENG":"You'd better come up with a good opening statement.","TWN":"建議你們最好找個好一點的律師。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으으...... 역시 카린 양처럼 깐깐하시네요......","JPN":"むむ……さすが容赦ないところも、カリンさんにそっくり……","ENG":"Sheesh, you're just as difficult to please as Karin.","TWN":"呃……果然和卡琳小姐一樣固執啊……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아뇨. 감사합니다. 그 정도만 해도 더 바랄게 없어요.","JPN":"いいえ、ありがたい話です。それ以上の望みはありませんから。","ENG":"No. Thank you. I can't ask for more.","TWN":"不會，謝謝！這樣就夠了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럼 일단 다들 창고로 가시죠.","JPN":"では、皆さん、とりあえず倉庫へ向かいましょう。","ENG":"Now, let's go to the warehouse.","TWN":"那麼大家先去一趟倉庫吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"창고요......?","JPN":"倉庫……？","ENG":"The warehouse?","TWN":"倉庫……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체라니...... 그런 존재와 맨몸으로 싸울 순 없습니다.","JPN":"第4種侵食体を相手に、裸一貫で戦うわけにはいきません。","ENG":"You said a Category 4 C.O. You can't fight it bare-handed.","TWN":"那是第4級侵蝕體……我們總不能赤手空拳地和它戰鬥吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다행히 이곳은 관리국의 이터니움 기술을 연구하는 곳입니다.","JPN":"幸いなことに、ここは管理局のエタニウム技術を研究するところです。","ENG":"Fortunately for us, this is where we study the Eternium technologies of the Administration.","TWN":"幸好這裡曾經是管理局研究永恆之金的地方。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래서 테크 레벨 4단계의 최고급 대 침식전 장비들도 다수 보유하고 있죠.","JPN":"そのおかげで、テックレベル4の最上級侵食戦装備も多数保持しています。","ENG":"It's got a wide selection of the finest Tech Level 4 anti-Corruption gear.","TWN":"所以還留有大部分的裝備，而且還是科技等級4的最高級對侵蝕戰裝備。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"연구용 프로토 타입들이긴 하지만 당연히 실전에서도 효과적일 겁니다.","JPN":"研究用のプロトタイプではありますが、当然実戦でも効果を発揮できるはずです。","ENG":"Most of them are experimental prototypes, but still they can be helpful in combat.","TWN":"雖然都是研究用的原型，不過用來實戰肯定也沒問題。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니까 창고에서 당신들이 쓸 만한 것들을 찾아보도록 하죠.","JPN":"ですから、倉庫であなた方が使いやすそうなものを探してみましょう。","ENG":"So, let's pick something you can use from the warehouse.","TWN":"所以去倉庫找找你們能用的吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와! 그거 멋지네요!","JPN":"おお！　それは素晴らしい！","ENG":"Whoa, that'd be awesome!","TWN":"哇！那真是太帥了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이 정도의 발전된 기술로 만든 장비는 어떤 성능일지 벌써 기대되는데요?","JPN":"ここまで進んでいる技術で制作された装備だなんて、どんな性能か楽しみですね！","ENG":"I can't wait to try out gear made with such advanced technology like this!","TWN":"用最先進的技術製作的裝備，性能會是什麼樣的呀，好期待喔？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......너무 기대는 마십시오.","JPN":"……あまり期待しすぎないほうが良いと思います。","ENG":"Don't expect too much, though.","TWN":"……請不要抱有太大期待。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체를 상대로 얼마나 버틸 수 있을지는 모르니까요.","JPN":"第4種侵食体を相手に、どこまで持ちこたえられるかは未知数ですから。","ENG":"I don't know how long it can last against Category 4 C.O.","TWN":"畢竟是以4級侵蝕體為對手，不知道能撐多久。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 아까 그 사람은 쉽게 처리할 수 있다고 하시던데요?","JPN":"え？　さっきの人は簡単に片づけられると言ってましたよ？","ENG":"Huh? But the others said they could easily take care of it.","TWN":"咦？剛才有人說很好對付的耶？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"무슨 말도 안 되는 소리입니까?","JPN":"そんなわけないです。","ENG":"That's nonsense.","TWN":"說什麼鬼話？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체라면 이쪽 세계에서도 매우 심각한 위협입니다.","JPN":"第4種侵食体は、この世界にとっても、非常に深刻な脅威です。","ENG":"Category 4 C.O.s are serious threats in this world as well.","TWN":"就算是這邊的世界，4級侵蝕體也非常危險。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"세계 멸망을 걱정해야 할 정도의 재앙은 당연히 아닙니다만......","JPN":"もちろん、世界滅亡を案ずるほどの存在ではありませんが……","ENG":"They're not so serious that they threaten the existence of the world, of course,","TWN":"當然還沒到毀滅世界的程度……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이렇게 몇몇 용병들이 모여서 막을 수 있는 종류의 적도 아닙니다.","JPN":"こうやって数人の傭兵だけで始末できるような敵でもありません。","ENG":"but they're not easy to take care of with as few mercenaries as this.","TWN":"但也不是光靠幾個傭兵就能對付的敵人。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니 우리의 목표는 시간을 끄는 겁니다.","JPN":"ですから、僕たちの目標は時間稼ぎです。","ENG":"Our goal is to stall for time.","TWN":"我們的首要任務是拖延時間。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시간을요?","JPN":"時間稼ぎ？","ENG":"To stall for time?","TWN":"拖延時間？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네. 최대한 놈을 붙잡고 시간을 끌면서......","JPN":"はい、できるだけ奴を引き留めて、時間稼ぎをしながら……","ENG":"Yes. We'll keep it busy for as long as we can","TWN":"對。一邊盡可能拖住它……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이상 상황을 알아 챈 중장님과 대령님이 오시기를 기다려야 합니다.","JPN":"異常に気づいた中将や大佐が駆け付けるのを待つのです。","ENG":"until the Lieutenant General and the Colonel come to our rescue.","TWN":"一邊等待獲知以上情況的中將大人和上校大人過來。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그분들이라면...... 제 4종 침식체 정도는 충분히 쓰러트릴 수 있겠죠.","JPN":"あの二人なら……第4種侵食体くらいは十分倒せるでしょうからね。","ENG":"They should be able to take care of that Category 4 C.O.","TWN":"他們的話……肯定能打倒4級侵蝕體。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니까 그때까지 버틸 수 있도록 준비에 만전을 다해야 합니다.","JPN":"それまではなんとか持ちこたえられるように、万全を期して備えなければなりません。","ENG":"So, let's arm ourselves as best as we can.","TWN":"所以為了能夠撐到那個時候，我們要做好萬全的準備。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"빨리 따라오세요!","JPN":"早くついてきてください！","ENG":"Come on, follow me!","TWN":"請快點跟上！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"O-okay!","TWN":"是，知道了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네네~ 알겠습니다.","JPN":"はいはい～わかりましたよ。","ENG":"Okay, okay, we're coming."},"stage":{"bg":"HANGAR","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......드디어 나타났군요.","JPN":"……ついに、現れましたね。","ENG":"Finally, it's here.","TWN":"……終於出現了啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데......","JPN":"ところで……","ENG":"And...","TWN":"不過……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"꽤 특이한 형태네요? 기존 관리국 분류 카테고리에 없는 타입 같은데......","JPN":"ずいぶん変わった形ですね？　管理局の従来カテゴリーに属さないタイプのようですが……","ENG":"It looks pretty peculiar. I don't think I've seen anything like it in the Administration's C.O. categories.","TWN":"樣子還挺奇怪的耶？好像是管理局侵蝕體分類列表裡沒有的類型……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 본 적 있으신가요?","JPN":"師匠は見たことありますか？","ENG":"Have you, Master?","TWN":"師父妳有見過嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......저건?","JPN":"……あれは？","ENG":"That's...","TWN":"……那個？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님......?","JPN":"師匠……？","ENG":"Master?","TWN":"師父……？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니...... 비슷하긴 하지만 다르군......","JPN":"いや……似てるけど、別物だな……","ENG":"No. It's similar, but not exactly the same.","TWN":"不……很像，但是不一樣……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그저...... 희석된 피에서 태어난 퇴화체일 뿐인가?","JPN":"血の一部から派生した劣化版に過ぎないか？","ENG":"I wonder if it's a degenerated form, born from diluted blood.","TWN":"只是……血統被稀釋的退化體嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"퇴화체? 무슨 말씀이시죠?","JPN":"劣化版？　何のことですか？","ENG":"A degenerated form? What do you mean?","TWN":"退化體？妳在說什麼啊？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 아무것도 아니다.","JPN":"いや、何でもない。","ENG":"No, nothing.","TWN":"不，沒什麼。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"조금...... 안 좋은 옛 기억이 떠올랐을 뿐이야.","JPN":"少しだけ……昔の悪夢がちらついただけだ。","ENG":"I just remembered something unpleasant.","TWN":"只是稍微……想起了不好的回憶而已。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저건......","JPN":"あれは……","ENG":"That's...","TWN":"這……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"피부에 닿는 감각만으로도 알겠습니다. 확실히 제 4종 침식체로군요.","JPN":"感覚だけでわかります。間違いなく、第4種侵食体ですね。","ENG":"I can tell just by the sensation on my skin that is definitely a Category 4 C.O.","TWN":"光是肌膚感受到的感覺就曉得了，它確實是4級侵蝕體呢。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 준비됐나?","JPN":"みんな、準備はいいか？","ENG":"Guys, are you ready?","TWN":"大家都準備好了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼요! 태어난 후로 제일 화끈하게 놀아볼 생각이에요!","JPN":"もちろん！　これまで生きてきたなかで、もっとも熱く遊んでやりますよ！","ENG":"Absolutely! I'm as ready as I'll ever be!","TWN":"當然。我開始熱血沸騰了！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 만전입니다! 후방은 염려 마시길!","JPN":"私も準備万端です！　後方はご心配なく！","ENG":"So am I. Know that I've got your back.","TWN":"我也準備好了！後方請交給我！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 정말 당신들 두 명이서 정면으로 싸울 생각입니까?","JPN":"でも、本当に二人で正面から戦うつもりですか？","ENG":"But are you sure you two can take it head-on?","TWN":"不過你們兩個人真的打算正面交鋒嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 보기엔 무모한 짓입니다. 얌전히 저희와 함께 방어전을 진행하는 것이......","JPN":"僕は無謀だと思います。おとなしく僕たちとともに防御戦に備えたほうが……","ENG":"I think you're being reckless. You should just stay with us and focus on defending—","TWN":"在我眼中這是非常魯莽的行為。你們還是乖乖和我們一起退到後方進行防衛戰……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무모한지 어떤지는 싸워보면 알게 되겠지.","JPN":"無謀かどうかは戦ってみないとわからないだろ。","ENG":"We'll see whether or not we're being reckless.","TWN":"是不是魯莽，打起來你就知道了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 간다! 잘 따라오도록!","JPN":"さあ、行くぞ！　遅れるなよ！","ENG":"Alright then, here I go. Don't fall too far behind.","TWN":"那就走吧！好好跟上！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마시죠, 스승님. 발밑 조심하시고요.","JPN":"心配無用ですよ、師匠。足元気をつけてくださいね。","ENG":"Don’t worry, Master. And watch your step.","TWN":"別擔心，師父，還請小心腳下。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};